mapper.sql:
SELECT M1.ID, M1.STOP_REASON_CLASS_CODE, d.DICT_LABEL STOP_REASON_CLASS_LABEL, M1.STOP_REASON_TYPE_CODE, e.DICT_LABEL STOP_REASON_TYPE_LABEL, M1.STOP_REASON_NAME, M1.SHORTHAND_CODE, M1.SORT_NUM, M1.CREATE_BY, M1.CREATE_BY_NAME, M1.CREATE_TIME FROM M_STOP_REASON M1 left join M_DICT_DATA d ON M1.STOP_REASON_CLASS_CODE=d.DICT_VALUE and d.DICT_TYPE='STOP_REASON_CLASS' left join M_DICT_DATA e ON M1.STOP_REASON_TYPE_CODE=e.DICT_VALUE and e.DICT_TYPE='STOP_REASON_TYPE'
and M1.STOP_REASON_CLASS_CODE = #{stopReasonClassCode}
and M1.STOP_REASON_NAME LIKE #{stopReasonName}
and M1.STOP_REASON_TYPE_CODE = #{stopReasonTypeCode}
